// ---- Column: Vertical layout ----
@Composable
fun ColumnExamples() {
    // Basic column
    Column(
        modifier = Modifier.padding(16.dp)
    ) {
        Text("Item 1")
        Text("Item 2")
        Text("Item 3")
    }

    // Column with spacing
    Column(
        modifier = Modifier.padding(16.dp),
        verticalArrangement = Arrangement.spacedBy(16.dp)
    ) {
        Text("Spaced item 1")
        Text("Spaced item 2")
        Text("Spaced item 3")
    }

    // Column with alignment
    Column(
        modifier = Modifier
            .fillMaxWidth()
            .padding(16.dp),
        horizontalAlignment = Alignment.CenterHorizontally,
        verticalArrangement = Arrangement.Center
    ) {
        Text("Centered item")
        Text("Also centered")
    }

    // Column with weight
    Column(
        modifier = Modifier
            .fillMaxHeight()
            .padding(16.dp)
    ) {
        Text(
            text = "This takes 1/3",
            modifier = Modifier
                .fillMaxWidth()
                .weight(1f)
                .background(Color.LightGray)
        )
        Text(
            text = "This takes 2/3",
            modifier = Modifier
                .fillMaxWidth()
                .weight(2f)
                .background(Color.Cyan)
        )
    }
}

