// ---- Box: Stacking layout ----
@Composable
fun BoxExamples() {
    // Basic box
    Box(
        modifier = Modifier
            .size(200.dp)
            .background(Color.LightGray)
    ) {
        Text("Top left")
    }

    // Box with alignment
    Box(
        modifier = Modifier
            .size(200.dp)
            .background(Color.LightGray),
        contentAlignment = Alignment.Center
    ) {
        Text("Centered")
    }

    // Box with multiple elements (stacked)
    Box(
        modifier = Modifier
            .size(200.dp)
            .background(Color.LightGray)
    ) {
        // Background
        Box(
            modifier = Modifier
                .fillMaxSize()
                .background(Color.Blue)
        )
        // Foreground
        Text(
            text = "Foreground",
            color = Color.White,
            modifier = Modifier.align(Alignment.Center)
        )
    }

    // Box with custom positioning
    Box(
        modifier = Modifier
            .size(200.dp)
            .background(Color.LightGray)
    ) {
        Text(
            text = "Top Left",
            modifier = Modifier.align(Alignment.TopStart)
        )
        Text(
            text = "Top Right",
            modifier = Modifier.align(Alignment.TopEnd)
        )
        Text(
            text = "Bottom Left",
            modifier = Modifier.align(Alignment.BottomStart)
        )
        Text(
            text = "Bottom Right",
            modifier = Modifier.align(Alignment.BottomEnd)
        )
        Text(
            text = "Center",
            modifier = Modifier.align(Alignment.Center)
        )
    }

    // Box with constraints
    Box(
        modifier = Modifier
            .fillMaxSize()
            .padding(16.dp)
    ) {
        // Background image
        Image(
            painter = painterResource(id = R.drawable.background),
            contentDescription = null,
            modifier = Modifier.fillMaxSize(),
            contentScale = ContentScale.Crop
        )
        // Overlay
        Column(
            modifier = Modifier
                .fillMaxSize()
                .background(Color.Black.copy(alpha = 0.5f))
                .padding(16.dp)
        ) {
            Text(
                text = "Overlay Text",
                color = Color.White,
                fontSize = 24.sp
            )
            Text(
                text = "This is on top of the image",
                color = Color.White
            )
        }
    }
}

// ---- Nested layouts ----
@Composable
fun NestedLayouts() {
    Column(
        modifier = Modifier
            .fillMaxSize()
            .padding(16.dp),
        verticalArrangement = Arrangement.spacedBy(16.dp)
    ) {
        // Row at top
        Row(
            modifier = Modifier.fillMaxWidth(),
            horizontalArrangement = Arrangement.SpaceEvenly
        ) {
            Text("Home")
            Text("Search")
            Text("Profile")
        }

        // Main content
        Box(
            modifier = Modifier
                .weight(1f)
                .background(Color.LightGray)
        ) {
            Text(
                text = "Main Content",
                modifier = Modifier.align(Alignment.Center)
            )
        }

        // Row at bottom
        Row(
            modifier = Modifier.fillMaxWidth(),
            horizontalArrangement = Arrangement.SpaceEvenly
        ) {
            Text("Footer 1")
            Text("Footer 2")
            Text("Footer 3")
        }
    }
}

