@Composable
fun BrokenLayout() {
    // 1. Column with no modifier -> content overflows
    Column {
        Text("Item 1")
        Text("Item 2")
        Text("Item 3")
    }

    // 2. Row with wrong arrangement
    Row(
        modifier = Modifier.fillMaxWidth(),
        horizontalArrangement = Arrangement.SpaceEvenly
    ) {
        Text("Left")
        Text("Center")
        Text("Right")
    }

    // 3. Box with overlapping content
    Box {
        Text("Background")
        Text("Foreground")
    }

    // 4. Weight without parent constraint
    Text(
        text = "This will crash",
        modifier = Modifier.weight(1f)  // Error!
    )
}

phase2.explanation:
🤖 **Common layout mistakes and how to fix them.**

| Mistake | Fix |
|---------|-----|
| No scrolling | Add `verticalScroll(rememberScrollState())` |
| Wrong arrangement | Use appropriate Arrangement |
| Overlapping content | Use alignment or spacing |
| Weight without constraint | Use in Column or Row with fillMaxSize |

**Fixes:**
```kotlin
// 1. Add scrolling
Column(
    modifier = Modifier
        .fillMaxSize()
        .verticalScroll(rememberScrollState())
) {
    // content
}

// 2. Use proper arrangement
Row(
    modifier = Modifier.fillMaxWidth(),
    horizontalArrangement = Arrangement.SpaceEvenly
) {
    // content
}

// 3. Use alignment in Box
Box(
    modifier = Modifier.size(200.dp).background(Color.LightGray)
) {
    Text(
        text = "Foreground",
        modifier = Modifier.align(Alignment.Center)
    )
}

// 4. Weight in parent
Column(
    modifier = Modifier.fillMaxHeight()
) {
    Text(
        text = "Weighted",
        modifier = Modifier.weight(1f)
    )
}
```

**Kotlin-chan says:**
"Column, Row, Box. Use them wisely. Check constraints."

